class ConvexHull4D:
    def __init__(self, points):
        self.points = points
        self.dimensions = 4
        self.validate_points()

    def validate_points(self):
        for point in self.points:
            if len(point) != self.dimensions:
                raise ValueError("All points must be of four dimensions")

    def calculate_convex_hull(self):
        from scipy.spatial import ConvexHull
        hull = ConvexHull(self.points)
        return hull

    def get_convex_hull_facets(self):
        hull = self.calculate_convex_hull()
        facets = hull.equations
        return facets

    def get_convex_hull_vertices(self):
        hull = self.calculate_convex_hull()
        vertices = hull.vertices
        return vertices


class ConvexHull4DOutput:
    def __init__(self, facets, vertices):
        self.facets = facets
        self.vertices = vertices


