import numpy as np
from scipy.spatial import ConvexHull

class Point4D:
    def __init__(self, x, y, z, w):
        self.x = x
        self.y = y
        self.z = z
        self.w = w

    def to_array(self):
        return np.array([self.x, self.y, self.z, self.w])

def calculate_convex_hull(points):
    if not all(isinstance(point, (list, tuple, Point4D)) for point in points):
        raise ValueError("All points must be lists, tuples, or Point4D objects")

    points = [point if isinstance(point, Point4D) else Point4D(*point) for point in points]

    if not all(len(point.to_array()) == 4 for point in points):
        raise ValueError("All points must be 4D")

    points_array = np.array([point.to_array() for point in points])

    hull = ConvexHull(points_array)

    return hull

