class ConvexHull:
    def __init__(self, points):
        self.points = points
        self.hull = []

    def calculate_hull(self):
        if len(self.points) < 1:
            return self.hull

        if len(self.points) == 1:
            self.hull.append(self.points[0])
            return self.hull

        if len(self.points) == 2:
            self.hull.append(self.points[0])
            self.hull.append(self.points[1])
            return self.hull

        if len(self.points) == 3:
            self.hull.append(self.points[0])
            self.hull.append(self.points[1])
            self.hull.append(self.points[2])
            return self.hull

        self.points.sort(key=lambda p: (p.x, p.y, p.z, p.w))
        self.hull.append(self.points[0])
        self.hull.append(self.points[1])
        self.hull.append(self.points[2])

        for i in range(3, len(self.points)):
            while len(self.hull) > 1 and not self.is_ccw(self.hull[-2], self.hull[-1], self.points[i]):
                self.hull.pop()
            self.hull.append(self.points[i])

        return self.hull

    def is_ccw(self, p1, p2, p3):
        v1 = (p2.x - p1.x, p2.y - p1.y, p2.z - p1.z, p2.w - p1.w)
        v2 = (p3.x - p1.x, p3.y - p1.y, p3.z - p1.z, p3.w - p1.w)
        cross_product = (v1[1]*v2[2] - v1[2]*v2[1], v1[2]*v2[3] - v1[3]*v2[2], v1[3]*v2[1] - v1[1]*v2[3], v1[0]*v2[3] - v1[3]*v2[0])
        if cross_product[0] > 0 or (cross_product[0] == 0 and cross_product[1] > 0) or (cross_product[0] == 0 and cross_product[1] == 0 and cross_product[2] > 0) or (cross_product[0] == 0 and cross_product[1] == 0 and cross_product[2] == 0 and cross_product[3] > 0):
            return True
        return False

