class Point:
    def __init__(self, x, y, z, w):
        self.x = x
        self.y = y
        self.z = z
        self.w = w

class ConvexHull:
    def __init__(self, points):
        self.points = points
        self.hull = []

    def orientation(self, p, q, r):
        val = (q.y - p.y) * (r.x - q.x) - (q.x - p.x) * (r.y - q.y)
        if val == 0:
            return 0  # Collinear
        elif val > 0:
            return 1  # Clockwise
        else:
            return 2  # Counterclockwise

    def convex_hull(self, points):
        n = len(points)
        if n < 3:
            raise ValueError("Convex hull not possible")

        hull = []
        l = 0
        for i in range(1, n):
            if points[i].x < points[l].x:
                l = i

        p = l
        while True:
            hull.append(points[p])
            q = (p + 1) % n

            for i in range(n):
                if self.orientation(points[p], points[i], points[q]) == 2:
                    q = i

            p = q
            if p == l:
                break

        return hull

    def calculate_hull(self):
        if not all(len(point) == 4 for point in self.points):
            raise ValueError("All points must be 4D")

        points = [Point(*point) for point in self.points]
        self.hull = self.convex_hull(points)
        return self.hull

    def get_hull(self):
        return [(point.x, point.y, point.z, point.w) for point in self.hull]

def convex_hull_4d(points):
    hull = ConvexHull(points)
    hull.calculate_hull()
    return hull.get_hull()

