import numpy as np
from scipy.spatial import ConvexHull

class ConvexHull4D:
    def __init__(self, points):
        self.points = np.array(points)
        self.validate_input()

    def validate_input(self):
        if len(self.points.shape) != 2 or self.points.shape[1] != 4:
            raise ValueError("All points must be 4D")

    def calculate_convex_hull(self):
        hull = ConvexHull(self.points)
        return hull

    def get_convex_hull_vertices(self):
        hull = self.calculate_convex_hull()
        return self.points[hull.vertices]

    def get_convex_hull_simplices(self):
        hull = self.calculate_convex_hull()
        return hull.simplices

    def get_convex_hull_equations(self):
        hull = self.calculate_convex_hull()
        equations = []
        for simplex in hull.simplices:
            normal = np.cross(self.points[simplex[1]] - self.points[simplex[0]], self.points[simplex[2]] - self.points[simplex[0]])
            normal = np.append(normal, -np.dot(normal, self.points[simplex[0]]))
            equations.append(normal)
        return np.array(equations)

