import numpy as np

class ConvexHull:
    def __init__(self, points):
        self.points = np.array(points)
        self.n = len(points)
        self.dim = len(points[0])
        if self.dim != 4:
            raise ValueError("All points must be of four dimensions")

    def orientation(self, p, q, r):
        val = np.linalg.det(np.array([q-p, r-q, np.cross(q-p, r-q), np.cross(q-p, np.cross(q-p, r-q))]))
        if val == 0:
