import numpy as np

class ConvexHull:
    def __init__(self, points):
        self.points = np.array(points)
        self.dimensions = self.points.shape[1]
        self.convex_hull = self.calculate_convex_hull()

    def calculate_convex_hull(self):
        if self.dimensions!= 4:
            raise ValueError("Convex hull calculation is only supported for 4D points")

        if len(self.points) < 4:
            return self.points

        hull = []
        for point in self.points:
            if not self.is_inside(point, hull):
                hull = self.update_hull(point, hull)

        return np.array(hull)

    def is_inside(self, point, hull):
        if not hull.size:
            return False

        for i in range(len(hull)):
            normal = self.calculate_normal(hull, point)
            if np.dot(normal, point - hull[i]) < 0:
                return False

        return True

    def update_hull(self, point, hull):
        new_hull = []
        for p in hull:
            if self.is_visible(p, point, hull):
                new_hull.append(p)

        new_hull.append(point)
        return new_hull

    def is_visible(self, p1, p2, hull):
        if not hull.size:
            return True

        for i in range(len(hull)):
            normal = self.calculate_normal(hull, p1)
            if np.dot(normal, p2 - hull[i]) < 0:
                return False

        return True

    def calculate_normal(self, hull, point):
        if len(hull) < 3:
            return np.array([0, 0, 0, 0])

        v1 = hull[0] - point
        v2 = hull[1] - point
        v3 = hull[2] - point

        normal = np.cross(np.cross(v1, v2), v3)
        return normal / np.linalg.norm(normal)

    def get_convex_hull(self):
        return self.convex_hull

