class Tree:
    def __init__(self, root):
        self.root = Node(root)

    def add_child(self, parent_value, child_value):
        parent = self.find_node(parent_value)
        if parent:
            parent.children.append(Node(child_value))

    def find_node(self, value, node=None):
        if not node:
            node = self.root
        if node.value == value:
            return node
        for child in node.children:
            found_node = self.find_node(value, child)
            if found_node:
                return found_node
        return None

    def print_tree(self, node=None, level=0):
        if not node:
            node = self.root
        print('  ' * level + str(node.value))
        level += 1
        for child in node.children:
            self.print_tree(child, level)

