def calculate_item_frequencies(data, categories):
    frequencies = {}
    for category in categories:
        frequencies[category] = 0
        for item in data:
            if item['category'] == category:
                frequencies[category] += 1
    return frequencies

def calculate_average_frequencies(frequencies, data):
    average_frequencies = {}
    total_frequencies = sum(frequencies.values())
